fn string_to_number(&mut self, idx: i32) -> Option<usize> {
    let bytes = lua_vm::api::to_lua_string(self, idx)
        .ok()
        .flatten()?
        .as_bytes()
        .to_vec();
    let consumed = lua_vm::api::string_to_number(self, &bytes);
    if consumed == 0 {
        None
    } else {
        Some(consumed)
    }
}

