fn aux_set_str(state: &mut LuaState, t: LuaValue, k: &[u8]) -> Result<(), LuaError> {
    // C: TString *str = luaS_new(L, k); api_checknelems(L, 1);
    let str_val = {
        let ts = state.intern_str(k)?;
