        let mut remaining = Some(chunk.to_vec());
        let reader: Box<dyn FnMut() -> Option<Vec<u8>>> = Box::new(move || remaining.take());
        let status = lua_vm::api::load(self, reader, Some(name), mode)?;
        Ok(status == LuaStatus::Ok)
